     1→#!/usr/bin/env bun
     2→
     3→/**
     4→ * Ralph Loop - Automated Claude Code Task Executor
     5→ *
     6→ * Based on Geoffrey Huntley's Ralph Wiggum technique:
     7→ * - Fresh context per iteration (new Claude instance each time)
     8→ * - Memory persists through files only (git, progress.txt)
     9→ * - One task per iteration
    10→ * - Completion signal terminates loop
    11→ *
    12→ * Uses Claude CLI's --output-format stream-json for real-time streaming.
    13→ *
    14→ * @see https://ghuntley.com/ralph/
    15→ */
    16→
    17→import { appendFileSync } from 'node:fs';
    18→import { chalk } from 'zx';
    19→
    20→function parseMaxIterations(arg: string | undefined): number {
    21→  const parsed = parseInt(arg ?? '100', 10);
    22→  if (isNaN(parsed) || parsed <= 0) {
    23→    console.error('Error: maxIterations must be a positive integer');
    24→    process.exit(1);
    25→  }
    26→  return parsed;
    27→}
    28→
    29→const CONFIG = Object.freeze({
    30→  maxIterations: parseMaxIterations(Bun.argv[2]),
    31→  delayBetweenIterations: 5000,
    32→  logFile: './loop.log',
    33→  progressFile: './.claude/progress.txt',
    34→  iterationTimeout: 600000, // 10 minutes max per iteration
    35→  // Dual-condition exit gate: requires explicit RALPH_STATUS with exit: true
    36→  exitPattern: /RALPH_STATUS:\s*\{[^}]*"exit":\s*true[^}]*\}/,
    37→});
    38→
    39→// Module-scope process reference for cleanup on signals
    40→let currentProc: ReturnType<typeof Bun.spawn> | null = null;
    41→
    42→const TASK_PROMPT = `Read \`./.claude/progress.txt\`, pick the most important pending task, execute it, update the file, commit, and stop.
    43→
    44→IMPORTANT RULES:
    45→- Do NOT change logic, only migrate structure
    46→- The source of truth is card-place, consult it only if in doubt
    47→- The code has already been copied to this repository
    48→- Everything must be migrated to the new architecture/Style Guide (./.claude/STYLE_GUIDE.md)
    49→
    50→WORKFLOW:
    51→1. Read progress.txt and identify the most important pending single task
    52→2. If NO pending tasks exist, signal completion (see OUTPUT STATUS below) and stop
    53→3. If there is a task:
    54→   a. Update task status to "in progress" in progress.txt
    55→   b. Execute task following STYLE_GUIDE.md
    56→   c. Launch 3 review agents to deeply review the work, giving
    57→      the entire context of the task, simulating pull request.
    58→   d. Review output and consider improvements
    59→   e. Implement corrections if needed
    60→   f. Update progress.txt marking task as completed
    61→   g. Commit task changes (not include unrelated code)
    62→   h. Output status block (see below)
    63→   i. Stop
    64→
    65→OUTPUT STATUS (REQUIRED at end of EVERY response):
    66→You MUST output this exact format at the END of your response:
    67→
    68→RALPH_STATUS: { "exit": <true if ALL tasks done, false otherwise>, "task": "<completed task name>", "remaining": <number of pending tasks> }
    69→
    70→Examples:
    71→- Task completed but more remain: RALPH_STATUS: { "exit": false, "task": "Create usePoints hook", "remaining": 5 }
    72→- ALL tasks completed: RALPH_STATUS: { "exit": true, "task": "Delete Redux files", "remaining": 0 }
    73→
    74→CRITICAL (THINK BEFORE ACTING):
    75→1. The FIRST thing you MUST do is write your understanding of each WORKFLOW statement
    76→2. The SECOND thing you MUST do is write your understanding of the work in progress described in progress.txt
    77→3. Only AFTER completing steps 1 and 2, proceed with the task execution
    78→4. If more work is necessary, add a new task to the file, set "exit": false, and Stop
    79→5. Only set "exit": true when ALL tasks in progress.txt are completed
    80→6. For multiple lint/typescript/test errors, fix just one error and register others in progress.txt to be fixed in the next iteration
    81→7. For @semparar/* packages, read the real js code because some types are not updated correctly.
    82→`;
    83→
    84→function log(message: string, color?: string): void {
    85→  const timestamp = new Date().toISOString().replace('T', ' ').slice(0, 19);
    86→  const line = `[${timestamp}] ${message}`;
    87→  const coloredLine = color ? chalk[color](line) : line;
    88→
    89→  console.log(coloredLine);
    90→  appendFileSync(CONFIG.logFile, line + '\n');
    91→}
    92→
    93→async function checkDependencies(): Promise<void> {
    94→  const result = await Bun.$`which claude`.quiet().nothrow();
    95→  if (result.exitCode !== 0) {
    96→    log("ERROR: 'claude' command not found. Install Claude Code CLI.", 'red');
    97→    process.exit(1);
    98→  }
    99→
   100→  const progressFile = Bun.file(CONFIG.progressFile);
   101→  if (!(await progressFile.exists())) {
   102→    log(`ERROR: Progress file not found: ${CONFIG.progressFile}`, 'red');
   103→    process.exit(1);
   104→  }
   105→}
   106→
   107→function printHeader(): void {
   108→  console.log();
   109→  console.log(chalk.blue(`==========================================`));
   110→  console.log(chalk.blue(`   Ralph Loop - Bun.js Edition`));
   111→  console.log(chalk.blue(`==========================================`));
   112→  console.log(`Max iterations: ${chalk.yellow(CONFIG.maxIterations)}`);
   113→  console.log(`Log file: ${chalk.yellow(CONFIG.logFile)}`);
   114→  console.log(
   115→    `Delay between iterations: ${chalk.yellow(`${CONFIG.delayBetweenIterations / 1000}s`)}`,
   116→  );
   117→  console.log();
   118→}
   119→
   120→/**
   121→ * Stream-JSON message types from Claude Code CLI
   122→ * @see https://gist.github.com/SamSaffron/603648958a8c18ceae34939a8951d417
   123→ * @see https://github.com/anthropics/claude-code/issues/733
   124→ */
   125→interface ContentBlock {
   126→  type: 'text' | 'tool_use' | 'tool_result';
   127→  text?: string;
   128→  name?: string;
   129→  input?: unknown;
   130→  content?: string;
   131→}
   132→
   133→interface StreamMessage {
   134→  type: 'system' | 'assistant' | 'user' | 'result' | 'stream_event' | 'message';
   135→  subtype?: string;
   136→  role?: 'assistant' | 'user';
   137→  // For stream_event type
   138→  event?: {
   139→    type: string;
   140→    delta?: {
   141→      type: string;
   142→      text?: string;
   143→    };
   144→  };
   145→  // For result type
   146→  result?: string;
   147→  // For assistant/user/message types
   148→  message?: {
   149→    role?: string;
   150→    content?: ContentBlock[];
   151→  };
   152→  // Direct content array (alternative format)
   153→  content?: ContentBlock[];
   154→}
   155→
   156→async function runIteration(): Promise<{
   157→  output: string;
   158→  exitCode: number;
   159→}> {
   160→  log('Executing Claude Code...');
   161→
   162→  const proc = Bun.spawn(
   163→    [
   164→      'claude',
   165→      '-p',
   166→      TASK_PROMPT,
   167→      '--verbose',
   168→      '--debug',
   169→      '--dangerously-skip-permissions',
   170→      '--output-format',
   171→      'stream-json',
   172→      '--include-partial-messages',
   173→    ],
   174→    {
   175→      cwd: process.cwd(),
   176→      env: process.env,
   177→      stdout: 'pipe',
   178→      stderr: 'inherit', // Pass through stderr to console
   179→    },
   180→  );
   181→
   182→  // Store proc reference for cleanup on signals
   183→  currentProc = proc;
   184→
   185→  let output = '';
   186→  let timedOut = false;
   187→  const decoder = new TextDecoder();
   188→  let buffer = '';
   189→  let hasContentInBlock = false;
   190→
   191→  // Iteration timeout
   192→  const timeoutId = setTimeout(() => {
   193→    timedOut = true;
   194→    log('Iteration timeout reached. Killing process...', 'yellow');
   195→    try {
   196→      proc.kill();
   197→    } catch {
   198→      // Process may have already exited
   199→    }
   200→  }, CONFIG.iterationTimeout);
   201→
   202→  const reader = proc.stdout.getReader();
   203→
   204→  try {
   205→    while (true) {
   206→      const { done, value } = await reader.read();
   207→      if (done) break;
   208→
   209→      buffer += decoder.decode(value, { stream: true });
   210→
   211→      // Process complete JSON lines
   212→      const lines = buffer.split('\n');
   213→      buffer = lines.pop() || ''; // Keep incomplete line in buffer
   214→
   215→      for (const line of lines) {
   216→        if (!line.trim()) continue;
   217→
   218→        try {
   219→          const msg: StreamMessage = JSON.parse(line);
   220→
   221→          // 1. Handle stream_event (real-time token streaming)
   222→          if (msg.type === 'stream_event') {
   223→            if (msg.event?.type === 'content_block_start') {
   224→              hasContentInBlock = false;
   225→            }
   226→            if (msg.event?.type === 'content_block_delta') {
   227→              const text = msg.event.delta?.text;
   228→              if (text) {
   229→                process.stdout.write(text);
   230→                output += text;
   231→                hasContentInBlock = true;
   232→              }
   233→            }
   234→            if (msg.event?.type === 'content_block_stop' && hasContentInBlock) {
   235→              process.stdout.write('\n');
   236→              output += '\n';
   237→              hasContentInBlock = false;
   238→            }
   239→          }
   240→
   241→          // 2. Handle assistant/message types (full messages with content arrays)
   242→          // This captures sub-agent outputs and tool results
   243→          if (msg.type === 'assistant' || msg.type === 'message') {
   244→            const contentBlocks = msg.message?.content ?? msg.content;
   245→            if (contentBlocks && Array.isArray(contentBlocks)) {
   246→              for (const block of contentBlocks) {
   247→                if (block.type === 'text' && block.text) {
   248→                  process.stdout.write(block.text);
   249→                  output += block.text;
   250→                  process.stdout.write('\n');
   251→                  output += '\n';
   252→                }
   253→              }
   254→            }
   255→          }
   256→
   257→          // 3. Handle user messages (tool results)
   258→          if (msg.type === 'user') {
   259→            const contentBlocks = msg.message?.content ?? msg.content;
   260→            if (contentBlocks && Array.isArray(contentBlocks)) {
   261→              for (const block of contentBlocks) {
   262→                if (block.type === 'tool_result' && block.content) {
   263→                  // Tool results - print with prefix for visibility
   264→                  const resultText = `\n${chalk.reset.blackBright(block.content)}\n`;
   265→                  process.stdout.write(resultText);
   266→                  output += block.content;
   267→                  process.stdout.write('\n');
   268→                  output += '\n';
   269→                }
   270→              }
   271→            }
   272→          }
   273→
   274→          // 4. Handle result type - final output
   275→          if (msg.type === 'result' && msg.result) {
   276→            if (!output.trim()) {
   277→              output = msg.result;
   278→            }
   279→          }
   280→        } catch {
   281→          // Ignore JSON parse errors for incomplete/malformed lines
   282→        }
   283→      }
   284→    }
   285→
   286→    // Process any remaining buffer
   287→    if (buffer.trim()) {
   288→      try {
   289→        const msg: StreamMessage = JSON.parse(buffer);
   290→        if (msg.type === 'result' && msg.result) {
   291→          if (!output.trim()) output = msg.result;
   292→        }
   293→      } catch {
   294→        // Ignore
   295→      }
   296→    }
   297→  } finally {
   298→    clearTimeout(timeoutId);
   299→    reader.releaseLock();
   300→    currentProc = null;
   301→  }
   302→
   303→  if (timedOut) {
   304→    return {
   305→      output,
   306→      exitCode: 124,
   307→    }; // Standard timeout exit code
   308→  }
   309→
   310→  const exitCode = await proc.exited;
   311→  console.log(); // Newline after streaming output
   312→
   313→  return {
   314→    output,
   315→    exitCode,
   316→  };
   317→}
   318→
   319→async function main(): Promise<void> {
   320→  let cleanupCalled = false;
   321→
   322→  const cleanup = (signal: string) => {
   323→    if (cleanupCalled) return;
   324→    cleanupCalled = true;
   325→    console.log();
   326→    log(`Script interrupted by ${signal}. Cleaning up...`);
   327→
   328→    // Kill any running Claude process
   329→    if (currentProc) {
   330→      try {
   331→        currentProc.kill();
   332→      } catch {
   333→        // Process may have already exited
   334→      }
   335→    }
   336→
   337→    const exitCode = signal === 'SIGINT' ? 130 : 143;
   338→    process.exit(exitCode);
   339→  };
   340→
   341→  process.on('SIGINT', () => cleanup('SIGINT'));
   342→  process.on('SIGTERM', () => cleanup('SIGTERM'));
   343→
   344→  await checkDependencies();
   345→  printHeader();
   346→
   347→  log('Starting automated task loop...');
   348→
   349→  for (let iteration = 1; iteration <= CONFIG.maxIterations; iteration++) {
   350→    console.log();
   351→    console.log(chalk.green(`==========================================`));
   352→    log(`Iteration #${iteration} / ${CONFIG.maxIterations}`, 'green');
   353→    console.log(chalk.green(`==========================================`));
   354→    console.log();
   355→
   356→    const { output, exitCode } = await runIteration();
   357→
   358→    if (exitCode === 0) {
   359→      log('Claude Code execution completed successfully', 'green');
   360→    } else {
   361→      log(
   362→        `Claude Code exited with status ${exitCode}, checking output...`,
   363→        'yellow',
   364→      );
   365→    }
   366→
   367→    // Dual-condition exit gate: requires explicit RALPH_STATUS with exit: true
   368→    const hasExitSignal = CONFIG.exitPattern.test(output);
   369→    if (hasExitSignal) {
   370→      // Extract status for logging
   371→      const match = output.match(/RALPH_STATUS:\s*(\{[^}]*})/);
   372→      const status = match ? match[1] : 'unknown';
   373→      console.log();
   374→      console.log(chalk.green(`==========================================`));
   375→      log('ALL TASKS COMPLETED!', 'green');
   376→      log(`Exit status: ${status}`, 'green');
   377→      log(`Total iterations: ${iteration}`, 'green');
   378→      console.log(chalk.green(`==========================================`));
   379→      process.exit(0);
   380→    }
   381→
   382→    // More specific error detection - avoid false positives from "error handling", etc.
   383→    const hasErrors =
   384→      exitCode !== 0 ||
   385→      /(?:^|\n)\s*(?:Error:|ERROR:|Failed:|FAILED:)/m.test(output) ||
   386→      output.includes('claude: error');
   387→    if (hasErrors) {
   388→      log('Warning: Potential errors detected in output.', 'yellow');
   389→    }
   390→
   391→    if (iteration < CONFIG.maxIterations) {
   392→      console.log();
   393→      log(
   394→        `Waiting ${CONFIG.delayBetweenIterations / 1000} seconds before next iteration...`,
   395→      );
   396→      await Bun.sleep(CONFIG.delayBetweenIterations);
   397→    }
   398→  }
   399→
   400→  console.log();
   401→  console.log(chalk.red(`==========================================`));
   402→  log(`MAX ITERATIONS REACHED (${CONFIG.maxIterations})`, 'red');
   403→  log('Loop stopped - tasks may still be pending', 'red');
   404→  console.log(chalk.red(`==========================================`));
   405→  process.exit(1);
   406→}
   407→
   408→main();
   409→

